class Animal:
    def make_sound(self):
        pass  # Base method to be overridden

class Dog(Animal):
    def make_sound(self):
        print("Dog says: Woof!")

class Cat(Animal):
    def make_sound(self):
        print("Cat says: Meow!")

class Cow(Animal):
    def make_sound(self):
        print("Cow says: Moo!")

# Do not modify the code below. This function will be called during testing.
def default_test():
    animals = [Dog(), Cat(), Cow()]
    for animal in animals:
        animal.make_sound()  # Should call the make_sound method for each animal
